%[text] ## Evaluation of DQN vs Brute Force Localization Precision (Trajectory)
%% Evaluation of DQN vs Brute Force Localization Precision on Random Positions (CDF)
% Executed until Done/Terminate conditions are met
clc; clear all; close all;

fprintf('=== Initializing Random Deployment Environment ===\n'); %[output:1fe83716]
% 1. Add required codebase folders to path
addingPathParentFolderByName('code');

% 2. Load Parameters
Parameters;  %[output:5f1a3a2b] %[output:27a23586] %[output:6a55ab5c] %[output:27b098c8] %[output:5fcd4218] %[output:3a93db55] %[output:72b1fdc7] %[output:273026da] %[output:97e3e275] %[output:061600a8] %[output:5c714ad4]

% 3. Run Calibration (Requires Parameters to be in the workspace)
Calibration; %[output:4a1c699f]

% 4. Load the trained DQN agent
agent_path = fullfile('..', 'Dataset', 'dqn_agent_navigation_144_neurons_1_relu.mat');
if isfile(agent_path) %[output:group:27701c5b]
    load(agent_path, 'agent');
    fprintf('Trained agent successfully loaded.\n'); %[output:8bdc5572]
else
    error('Agent file not found. Ensure the Dataset folder is positioned correctly relative to this script.');
end %[output:group:27701c5b]

%%
%[text] ### DQN Agent and Brute Force (Trajectory)
%% Evaluation Setup
N_eval = 500; % Number of episodes (random positions) to evaluate

fprintf('Generating %d random Mobile Unit (MU) positions...\n', N_eval); %[output:0b73c879]
err_dqn = zeros(N_eval, 1);
err_bf  = zeros(N_eval, 1);
steps_taken_dqn = zeros(N_eval, 1);

for i = 1:N_eval %[output:group:741ab3c6]
    if mod(i, 50) == 0
        fprintf('Evaluating position %d / %d...\n', i, N_eval); %[output:61fd3ad3]
    end
    
    % 1. Generate a random MU position using the room boundaries from Calibration.m
    rx = EnvPars.MU_margin + (L_hall - 2*EnvPars.MU_margin) * rand();
    ry = EnvPars.MU_margin + (W_hall - 2*EnvPars.MU_margin) * rand();
    pos_MU_rand = [rx, ry, EnvPars.h_MU];
    
    % Compute true DOA for this random position using workspace position vars
    [psi_x_true, psi_y_true] = computePsiFromPos(pos_MU_rand, EnvPars);
    
    % 2. Mock a stationary "trajectory" up to the maximum safety limit
    EnvPars.psi_x_traj = repmat(psi_x_true, EnvPars.MaxStepsPerEpisode, 1);
    EnvPars.psi_y_traj = repmat(psi_y_true, EnvPars.MaxStepsPerEpisode, 1);
    
    % ---------------------------------------------------------
    % DQN AGENT EVALUATION (Run until Terminated / Done)
    % ---------------------------------------------------------
    % Reset environment for the new random position
    [obs, LoggedSignals] = resetFunction_deployment(EnvPars);
    
    isDone = false;
    step = 0;
    
    % Let the agent navigate until it reaches the done condition or hits the safety limit
    while ~isDone && step < EnvPars.MaxStepsPerEpisode
        step = step + 1;
        
        action_out = getAction(agent, {obs});
        action = action_out{1};
        if iscategorical(action) || iscell(action)
            action = double(action); 
        end
        
        % Step the environment
        try
            % Attempts to use native isDone if you updated your stepFunction_deployment
            [obs, reward, isDone_env, LoggedSignals] = stepFunction_deployment(action, LoggedSignals, EnvPars);
            isDone = logical(isDone_env);
        catch
            % Fallback for the 3-output version currently in your uploaded file
            [obs, reward, LoggedSignals] = stepFunction_deployment(action, LoggedSignals, EnvPars);
            
            % Synthetic Terminate Condition: 
            % Stop when the agent locks onto >= 95% of the global calibrated maximum
            if reward >= 0.9
                isDone = true;
            end
        end
    end
    
    % Record the number of steps it took to lock on
    steps_taken_dqn(i) = step;
    
    % Extract the final position estimate after the agent has converged/terminated
    pos_MU_rand_est = estimatePosFromAngles(LoggedSignals.psi_x, LoggedSignals.psi_y, EnvPars, pos_MU_rand);
    pos_est_dqn = estimatePosFromAngles(LoggedSignals.psi_x_est, LoggedSignals.psi_y_est, EnvPars, pos_MU_rand);
    err_dqn(i) = norm(pos_est_dqn(1:2) - pos_MU_rand_est(1:2))*1e2; % cm
        
    % ---------------------------------------------------------
    % BRUTE FORCE EVALUATION (Optimal Benchmark)
    % ---------------------------------------------------------
    a_psi_x   = exp(1i * psi_x_true * ((1:EnvPars.N_x)-1))';
    a_psi_y   = exp(1i * psi_y_true * ((1:EnvPars.N_y)-1))';
    a_psi_x_y = kron(a_psi_y, a_psi_x);
     
    best_power = -inf;
    best_psi_x_est = 0;
    best_psi_y_est = 0;
    
    % Exhaustive search over all phase configurations
    for t_psi = 1:EnvPars.T
        v0  = EnvPars.U_func(1:EnvPars.N, t_psi);
        Upsilon   = diag(v0');
        G_Upsilon = EnvPars.G * Upsilon;
        r   = sqrt(db2pow(EnvPars.SNR_dB)) * G_Upsilon * a_psi_x_y;

        power_vec = abs(r).^2;
        current_peak = max(power_vec);

        if current_peak > best_power
            best_power = current_peak;
            R = flipud(fliplr(reshape(abs(r), [EnvPars.N_x, EnvPars.N_y])))';
            [~, linear_idx] = max(R, [], 'all');
            n_psi_x_max = ceil(linear_idx/EnvPars.N_x);
            n_psi_y_max = linear_idx-(n_psi_x_max-1)*EnvPars.N_x;
            % R_2D = reshape(abs(r), [EnvPars.N_x, EnvPars.N_y]);
            % [~, idx] = max(R_2D, [], 'all');
            % [n_y_max, n_x_max] = ind2sub(size(R_2D), idx);
            
            % Map snapshot index to temporal coords
            t_psi_x_max = EnvPars.t_x(t_psi);
            t_psi_y_max = EnvPars.t_y(t_psi);

            best_psi_x_est = mod(2*pi * (n_psi_x_max + (t_psi_x_max) / EnvPars.T_x) / EnvPars.N_x, 2*pi);
            best_psi_y_est = mod(2*pi * (n_psi_y_max + (t_psi_y_max) / EnvPars.T_y) / EnvPars.N_y, 2*pi);
        end
    end
    
    % pos_MU_true = estimatePosFromAngles(psi_x_true, psi_y_true, EnvPars, pos_MU_true);
    pos_est_bf = estimatePosFromAngles(best_psi_x_est, best_psi_y_est, EnvPars, pos_MU_rand_est);
    err_bf(i) = norm(pos_est_bf(1:2) - pos_MU_rand_est(1:2))*1e2; % cm
end %[output:group:741ab3c6]

%%
%[text] ### Figures
% CDF
figure %[output:3b1e44a4]
hold on %[output:3b1e44a4]
h1 = cdfplot(err_dqn); %[output:3b1e44a4]
set(h1, 'LineWidth', 1.5); %[output:3b1e44a4]
grid on %[output:3b1e44a4]
h2 = cdfplot(err_bf); %[output:3b1e44a4]
set(h2, 'LineWidth', 1.5); %[output:3b1e44a4]
grid on %[output:3b1e44a4]

xlim([0, 200]) %[output:3b1e44a4]
xlabel('Precision [cm]', 'Interpreter', 'latex', 'FontSize', 14); %[output:3b1e44a4]
ylabel('CDF', 'Interpreter', 'latex', 'FontSize', 14); %[output:3b1e44a4]
title(''); %[output:3b1e44a4]
legend({'DQN Agent', 'Brute Force'}, 'Location', 'best', 'Interpreter', 'latex', 'FontSize', 14); %[output:3b1e44a4]
set(gca, 'Box', 'on', 'TickDir', 'out', 'LineWidth', 1, 'FontSize', 12); %[output:3b1e44a4]

% Boxplot
figure %[output:6e03376f]
g1 = repmat({'DQN agent'},N_eval,1);
g2 = repmat({'Brute force'},N_eval,1);
g = [g1; g2];
h3 = boxplot([err_dqn, err_bf], g); %[output:6e03376f]
set(h3, 'LineWidth', 1.5); %[output:6e03376f]
grid on %[output:6e03376f]

%%
%[text] ### Functions
function [psi_x, psi_y] = computePsiFromPos(pos_MU, EnvPars)
    % Geometry: vector from SIM to MU. SIM on the ceiling, array in the
    % horizontal (xy) plane, z-axis pointing down toward the floor.

    delta = pos_MU(:) - EnvPars.pos_SIM(:);   % column vector
    rng   = norm(delta);

    % Direction cosines along the array's x and y axes
    u_x = delta(1) / rng;
    u_y = delta(2) / rng;

    % Electrical angles (assuming d_y = d_x)
    psi_x = mod(2*pi * EnvPars.d_x * u_x / EnvPars.lambda, 2*pi);
    psi_y = mod(2*pi * EnvPars.d_x * u_y / EnvPars.lambda, 2*pi);
end

function pos_MU_est = estimatePosFromAngles(psi_x_est, psi_y_est, EnvPars, pos_MU_true)
    % 1. Shift phases back to principal domain [-pi, pi]
    psi_x_est = mod(psi_x_est + pi, 2*pi) - pi;
    psi_y_est = mod(psi_y_est + pi, 2*pi) - pi;

    phi_est = atan2(-psi_y_est, -psi_x_est);
    % phi_est = atan(psi_y_est*EnvPars.d_x/(psi_x_est*EnvPars.d_x))
    theta_est = asin(EnvPars.lambda/(2*pi)*sqrt(psi_x_est^2/EnvPars.d_x^2+psi_y_est^2/EnvPars.d_x^2));

    pos_MU_est(1) = (EnvPars.pos_SIM(3)-pos_MU_true(3))/tan(theta_est)*cos(phi_est)+EnvPars.pos_SIM(1);
    pos_MU_est(2) = (EnvPars.pos_SIM(3)-pos_MU_true(3))/tan(theta_est)*sin(phi_est)+EnvPars.pos_SIM(2);
    pos_MU_est(3) = pos_MU_true(3);
end

function addingPathParentFolderByName(targetName)
    % Recursively places target folders into the MATLAB path
    currFolder = pwd;
    found = false;
    while true
        [parentFolder, currentName] = fileparts(currFolder);
        if strcmpi(currentName, targetName)
            found = true;
            break;
        end
        if isempty(parentFolder) || strcmp(currFolder, parentFolder)
            break;
        end
        currFolder = parentFolder;
    end
    if found
        addpath(genpath(currFolder));
    else
        warning('Folder named "%s" not found in any parent directory.', targetName);
    end
end


